// A new note landed in the vault. The folder it landed in decides which agent
// owns it, i.e. which agent should be triggered to act on the handoff.
//   scratchpads -> ippang, projects -> kuli, memory -> pakprof
const routes = {
  ippang:  { url: 'http://host.docker.internal:8642/v1/chat/completions', model: 'deepseek/deepseek-v2-flash' },
  kuli:    { url: 'http://host.docker.internal:8643/v1/chat/completions', model: 'anthropic/claude-opus-4-8' },
  pakprof: { url: 'http://host.docker.internal:8644/v1/chat/completions', model: 'z-ai/glm-4.6' },
};
const ownerByFolder = { scratchpads: 'ippang', projects: 'kuli', memory: 'pakprof' };

const path = ($input.first().json.path || '').toString();
if (!path.endsWith('.md')) return [];

const m = path.match(/obsidian-vault\/(scratchpads|projects|memory)\//);
if (!m) return [];
const agent = ownerByFolder[m[1]];
const route = routes[agent];

// Path as the agent sees it on the host (agents run on the host, not in n8n).
const hostPath = path.replace('/data/obsidian-vault/', 'obsidian-vault/');
const prompt = `A new note was placed in your folder: ${hostPath}\nRead it, act on it, and record your result in your own vault folder. If the task should move to another agent, drop a note in that agent's folder.`;

return [{ json: { agent, folder: m[1], url: route.url, model: route.model, prompt, note: hostPath } }];
